// node_conv_242 : pointwise (1x1) conv2d, tiled-streaming contract.
//   IC=128, OC=512, IH=IW=OH=OW=28, SH=SW=1 (no stride), MP=4.
//   channel_tile=32 -> IN_BEATS=4, OUT_BEATS=16 per pixel.
//   OC_PASSES=128 -> latency = IN_BEATS + OC_PASSES*(MP*K_TOTAL + 6)
//                            = 4 + 128*518 = 66308 cycles.
module node_conv_242 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    // -------- Geometry --------
    localparam integer IC = 128, OC = 512;
    localparam integer IH = 28, IW = 28, OH = 28, OW = 28;
    localparam integer KH = 1, KW = 1;
    localparam integer K_TOTAL      = IC*KH*KW;                       // 128
    localparam integer MP           = 4;
    localparam integer OC_PASSES    = (OC + MP - 1) / MP;             // 128
    localparam integer CHANNEL_TILE = 32;
    localparam integer IN_BEATS     = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;  // 4
    localparam integer OUT_BEATS    = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;  // 16
    localparam integer TILE_BITS    = CHANNEL_TILE * 8;               // 256

    // -------- Quantization --------
    localparam integer SCALE_MULT  = 4312;
    localparam integer SCALE_SHIFT = 19;

    // -------- Datapath widths --------
    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + $clog2(K_TOTAL);
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = $clog2(SCALE_MULT + 1);
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style="block", ram_style="block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_242_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_242_bias.hex",    biases);
    end

    reg signed [7:0] in_latch [0:IC-1];

    localparam [2:0] ST_LOAD=3'd0, ST_RUNNING=3'd1, ST_BIAS=3'd2, ST_SCALE=3'd3, ST_OUTPUT=3'd4, ST_EMIT=3'd5;
    reg [2:0] state;

    reg [3:0]                  in_beat_idx;
    reg [4:0]                  out_beat_idx;
    reg [10:0]                 active_emit_count;
    reg [$clog2(OC_PASSES):0]  oc_group;
    reg [$clog2(MP):0]         lane_counter;
    reg [$clog2(K_TOTAL):0]    k_counter;

    reg signed [7:0]            weight_q, act_q;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg                         mac_valid_q1, mac_valid_q2;
    reg [$clog2(MP):0]          mac_lane_q1, mac_lane_q2;
    reg                         mac_done_issuing;

    reg signed [ACC_W-1:0]    acc0, acc1, acc2, acc3;
    reg signed [BIASED_W-1:0] biased0, biased1, biased2, biased3;
    reg signed [SCALED_W-1:0] scaled0, scaled1, scaled2, scaled3;
    reg signed [SCALED_W-1:0] v_tmp;

    reg [OC*8-1:0] out_pack;
    integer ch_idx;
    integer global_oc;

    always @(posedge clk) begin
        if (state == ST_LOAD && valid_in && ready_in) begin
            for (ch_idx = 0; ch_idx < CHANNEL_TILE; ch_idx = ch_idx + 1)
                in_latch[in_beat_idx*CHANNEL_TILE + ch_idx] <= data_in[ch_idx*8 +: 8];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state<=ST_LOAD; ready_in<=1'b1; valid_out<=1'b0; data_out<={256{1'b0}};
            in_beat_idx<=0; out_beat_idx<=0; active_emit_count<=0;
            oc_group<=0; lane_counter<=0; k_counter<=0;
            mac_valid_q1<=0; mac_valid_q2<=0; mac_lane_q1<=0; mac_lane_q2<=0; mac_done_issuing<=0;
            weight_q<=0; act_q<=0; mul_q<=0; v_tmp<=0; out_pack<={(OC*8){1'b0}};
            acc0<=0; acc1<=0; acc2<=0; acc3<=0;
            biased0<=0; biased1<=0; biased2<=0; biased3<=0;
            scaled0<=0; scaled1<=0; scaled2<=0; scaled3<=0;
        end else begin
            mac_valid_q1 <= 1'b0;
            mac_valid_q2 <= mac_valid_q1;
            mac_lane_q2  <= mac_lane_q1;
            if (mac_valid_q1) mul_q <= $signed(weight_q) * $signed(act_q);
            if (mac_valid_q2) begin
                case (mac_lane_q2)
                    3'd0: acc0 <= acc0 + mul_q;
                    3'd1: acc1 <= acc1 + mul_q;
                    3'd2: acc2 <= acc2 + mul_q;
                    3'd3: acc3 <= acc3 + mul_q;
                    default: ;
                endcase
            end
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx<=0; ready_in<=1'b0;
                            oc_group<=0; lane_counter<=0; k_counter<=0;
                            acc0<=0; acc1<=0; acc2<=0; acc3<=0;
                            mac_done_issuing<=1'b0; state<=ST_RUNNING;
                        end else in_beat_idx <= in_beat_idx + 1;
                    end
                end
                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q     <= weights[(oc_group*MP + lane_counter)*K_TOTAL + k_counter];
                        act_q        <= in_latch[k_counter];
                        mac_valid_q1 <= 1'b1;
                        mac_lane_q1  <= lane_counter;
                        if (k_counter == K_TOTAL - 1) begin
                            k_counter <= 0;
                            if (lane_counter == MP - 1) begin mac_done_issuing<=1'b1; lane_counter<=0; end
                            else lane_counter <= lane_counter + 1;
                        end else k_counter <= k_counter + 1;
                    end
                    if (mac_done_issuing && !mac_valid_q1 && !mac_valid_q2) state <= ST_BIAS;
                end
                ST_BIAS: begin
                    biased0 <= acc0 + biases[oc_group*MP + 0];
                    biased1 <= acc1 + biases[oc_group*MP + 1];
                    biased2 <= acc2 + biases[oc_group*MP + 2];
                    biased3 <= acc3 + biases[oc_group*MP + 3];
                    state <= ST_SCALE;
                end
                ST_SCALE: begin
                    scaled0 <= $signed(biased0) * $signed(SCALE_MULT_CONST);
                    scaled1 <= $signed(biased1) * $signed(SCALE_MULT_CONST);
                    scaled2 <= $signed(biased2) * $signed(SCALE_MULT_CONST);
                    scaled3 <= $signed(biased3) * $signed(SCALE_MULT_CONST);
                    state <= ST_OUTPUT;
                end
                ST_OUTPUT: begin
                    v_tmp = (scaled0 + (scaled0[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    global_oc = oc_group*MP + 0;
                    out_pack[global_oc*8 +: 8] <= (v_tmp>127)?8'sd127:(v_tmp<-128)?-8'sd128:v_tmp[7:0];
                    v_tmp = (scaled1 + (scaled1[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    global_oc = oc_group*MP + 1;
                    out_pack[global_oc*8 +: 8] <= (v_tmp>127)?8'sd127:(v_tmp<-128)?-8'sd128:v_tmp[7:0];
                    v_tmp = (scaled2 + (scaled2[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    global_oc = oc_group*MP + 2;
                    out_pack[global_oc*8 +: 8] <= (v_tmp>127)?8'sd127:(v_tmp<-128)?-8'sd128:v_tmp[7:0];
                    v_tmp = (scaled3 + (scaled3[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                    global_oc = oc_group*MP + 3;
                    out_pack[global_oc*8 +: 8] <= (v_tmp>127)?8'sd127:(v_tmp<-128)?-8'sd128:v_tmp[7:0];
                    if (oc_group == OC_PASSES - 1) begin
                        data_out     <= out_pack[0 +: TILE_BITS];
                        valid_out    <= 1'b1;
                        out_beat_idx <= 0;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group <= oc_group + 1;
                        lane_counter<=0; k_counter<=0;
                        acc0<=0; acc1<=0; acc2<=0; acc3<=0;
                        mac_done_issuing<=1'b0; state<=ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS - 1) begin
                        valid_out<=1'b0; ready_in<=1'b1; state<=ST_LOAD; out_beat_idx<=0;
                        if (active_emit_count == OH*OW - 1) active_emit_count <= 0;
                        else active_emit_count <= active_emit_count + 1;
                    end else begin
                        out_beat_idx <= out_beat_idx + 1;
                        data_out     <= out_pack[(out_beat_idx + 5'd1) * TILE_BITS +: TILE_BITS];
                        valid_out    <= 1'b1;
                    end
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
